var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아...... 하으으...... 추, 추워......","JPN":"はぁ……はぅぅ……さ、寒い……","ENG":"Ow... Brrr... I-I'm cold...","TWN":"哈啊……哈呃呃……好、好冷……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"자기 손에서 나온 냉기에 동상 걸린 거야?","JPN":"まさか、自分の手から出した冷気で凍えてる？","ENG":"Did you get frostbitten by the chilly air you just created?","TWN":"被自己手裡發出的冷氣凍傷了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"혹시 혼자 자기 다리에 걸려 넘어지는 타입?","JPN":"もしかして、自分の足につまずいて転ぶタイプ？","ENG":"Are you one of those types that trips over their own feet?","TWN":"難道妳是那種自找麻煩的類型？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"시, 시끄러워요! 첫 실전인데 그럴 수도 있죠!","JPN":"ち、違いますわ！　初めての実戦で緊張しただけですの！","ENG":"Sh-shut up! I told you, it was my first real combat.","TWN":"吵、吵死了！第一次實戰也是有可能會這樣的嘛！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"그랬어? 초보자치곤 나쁘지 않은 솜씨던데, 맥크레디 양?","JPN":"そう？　初心者の割にはなかなかの腕だったよ、マクレディーさん？","ENG":"Oh, was it? But you weren't half bad for a first timer, Ms. MacCready.","TWN":"是嗎？以新手來說，表現得還不錯嘛，麥克蕾蒂小姐？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"흥. 당신처럼 괴상한 차림새로 다니는 사람에게 칭찬 받아도 별로 기쁘진 않네요.","JPN":"フン。あなたみたいにおかしな格好で歩き回る人から褒められたって、全っ然嬉しくありませんわ。","ENG":"Hmpf. I won't be swayed by compliments from someone in a crazy outfit.","TWN":"哼，被妳這種奇裝異服的人稱讚，也沒什麼好高興的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......잠깐, 당신 지금 뭐라고 불렀죠? 제가 누군지 알고 있나요?","JPN":"……待ってください。今、何ておっしゃいました？　私が誰なのかご存じなのですか？","ENG":"Wait, what did you call me just now? Do you know who I am?","TWN":"……等等，妳剛才叫我什麼？妳知道我是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"그럼, 학회장이 널 마중 나가라고 여기로 보냈거든.","JPN":"もちろん。学会長にアンタを迎えに行くよう言われて来たからさ。","ENG":"Of course I do. The President sent me to pick you up.","TWN":"因為學會長要我來這裡接妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회장......?","JPN":"学会長……？","ENG":"President?","TWN":"學會長……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"절 어떻게 알아본 거죠? 어릴 때 떠나서 모습도 많이 달라졌을 텐데?","JPN":"どうして私だと分かったのです？\\nここに来るのは子どもの頃以来ですし、\\n成長して見た目も変わっていますのに……","ENG":"But how did you recognize me? I left when I was very young. I must have changed a lot.","TWN":"妳怎麼認出我的？我小時候離開這裡後，樣貌應改變很多了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"냉기를 사용하는 카운터라고 들었어. 이 근처에 그런 사람이 둘이나 있을 리 없잖아.","JPN":"冷気を使うカウンターだって聞いてるから。この辺りにそんな人が二人もいるわけないでしょ。","ENG":"I was told you were a Counter specializing in manipulating ice. It's hardly imaginable that there could be two such people here in this secluded forest, isn't it?","TWN":"我聽說是使用冷氣的制裁者，這附近不可能有兩個這樣的人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 내 이름은 리벳이야! 성은 비밀! 물어봐 줘서 고마워!","JPN":"ああ、アタシの名前はリベット！　名字は秘密！　聞いてくれてありがとね！","ENG":"By the way, my name is Rivet. And I won't tell you my last name. Thanks for not asking.","TWN":"啊，我的名字是里維！姓氏保密！謝謝妳問我！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 실례했네요.","JPN":"コホン、失礼。","ENG":"Kahem, excuse me.","TWN":"咳咳，失禮了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"레지나 맥크레디라고 해요. 함께 있는 동안 잘 부탁드립니다.","JPN":"レジーナ・マクレディーと申します。ご一緒する間、よろしくお願いいたします。","ENG":"I am Regina MacCready. I look forward to staying with you.","TWN":"我是蕾佳娜·麥克蕾蒂，在一起的這段時間就請多多指教了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......여기 그리 오래 머물지는 않겠지만요.","JPN":"……ここに長居するつもりはありませんが。","ENG":"Although I doubt it'll be for long.","TWN":"……雖然我不會在這裡停留太久。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그거야 두고 봐야 될 일 아니겠어?","JPN":"それは、まだ分からないんじゃない？","ENG":"We can't be sure about that, can we?","TWN":"那不是到時候才知道嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"자, 저택으로 안내해 줄게. 또 길 잃어 버리지 않게 얼른얼른 따라오라구.","JPN":"さてと、邸宅に案内するよ。また道に迷わないように、しっかりついて来な。","ENG":"Let's go. I'll get you to the mansion. Be careful not to get lost again, okay?","TWN":"那麼，我帶妳去宅邸吧。別又迷路了，快跟上來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};